export function eventsForCountry(country: Country, fromYear: number, toYear: number): CountryYearEvent[] {
  if (country === "INTL") return [];
  return COUNTRY_EVENTS.filter(
    (e) => e.country === country && e.year >= fromYear && e.year <= toYear,
  );
}
